#!/usr/bin/env bash
set -euo pipefail

# setup-opentelemetry.sh
# Scaffolds OpenTelemetry initialization for Node.js/TypeScript projects.
# Usage: ./setup-opentelemetry.sh <service-name> [output-dir]
#   service-name  – required, e.g. "payment-api"
#   output-dir    – optional, defaults to "src/telemetry"

SERVICE_NAME="${1:?Usage: $0 <service-name> [output-dir]}"
OUT_DIR="${2:-src/telemetry}"
FILE="$OUT_DIR/instrumentation.ts"

mkdir -p "$OUT_DIR"

cat > "$FILE" << 'TYPESCRIPT'
// ─────────────────────────────────────────────────────────────
// OpenTelemetry SDK bootstrap – generated by setup-opentelemetry.sh
// Service:
TYPESCRIPT

# Append dynamic service name
echo "// Service: $SERVICE_NAME" >> "$FILE"
echo "// ─────────────────────────────────────────────────────────────" >> "$FILE"

cat >> "$FILE" << 'TYPESCRIPT'

import { NodeSDK } from '@opentelemetry/sdk-node'
import { OTLPTraceExporter } from '@opentelemetry/exporter-trace-otlp-proto'
import { OTLPMetricExporter } from '@opentelemetry/exporter-metrics-otlp-proto'
import { OTLPLogExporter } from '@opentelemetry/exporter-logs-otlp-proto'
import { getNodeAutoInstrumentations } from '@opentelemetry/auto-instrumentations-node'
import { Resource } from '@opentelemetry/resources'
import {
  SemanticResourceAttributes,
  SemanticAttributes,
} from '@opentelemetry/semantic-conventions'
import { PeriodicExportingMetricReader } from '@opentelemetry/sdk-metrics'
import { BatchSpanProcessor } from '@opentelemetry/sdk-trace-base'
import { diag, DiagConsoleLogger, DiagLogLevel } from '@opentelemetry/api'

// ── Debug logging (set OTEL_LOG_LEVEL=debug to enable) ──────
if (process.env.OTEL_LOG_LEVEL === 'debug') {
  diag.setLogger(new DiagConsoleLogger(), DiagLogLevel.DEBUG)
}

// ── Resource attributes ─────────────────────────────────────
const resource = new Resource({
  [SemanticResourceAttributes.SERVICE_NAME]:
    process.env.OTEL_SERVICE_NAME ||
TYPESCRIPT

echo "    '$SERVICE_NAME'," >> "$FILE"

cat >> "$FILE" << 'TYPESCRIPT'
  [SemanticResourceAttributes.SERVICE_VERSION]:
    process.env.OTEL_SERVICE_VERSION || require('../../package.json').version,
  [SemanticResourceAttributes.DEPLOYMENT_ENVIRONMENT]:
    process.env.NODE_ENV || 'development',
})

// ── Exporters ────────────────────────────────────────────────
const traceExporter = new OTLPTraceExporter({
  url: process.env.OTEL_EXPORTER_OTLP_ENDPOINT || 'http://localhost:4318/v1/traces',
  headers: process.env.OTEL_EXPORTER_OTLP_HEADERS
    ? Object.fromEntries(
        process.env.OTEL_EXPORTER_OTLP_HEADERS.split(',').map((h) =>
          h.split('=').map((s) => s.trim())
        )
      )
    : undefined,
})

const metricExporter = new OTLPMetricExporter({
  url: process.env.OTEL_EXPORTER_OTLP_ENDPOINT || 'http://localhost:4318/v1/metrics',
})

const logExporter = new OTLPLogExporter({
  url: process.env.OTEL_EXPORTER_OTLP_ENDPOINT || 'http://localhost:4318/v1/logs',
})

// ── Metric reader ────────────────────────────────────────────
const metricReader = new PeriodicExportingMetricReader({
  exporter: metricExporter,
  exportIntervalMillis:
    parseInt(process.env.OTEL_METRIC_EXPORT_INTERVAL_MS || '') || 60_000,
})

// ── SDK instance ─────────────────────────────────────────────
const sdk = new NodeSDK({
  resource,
  traceExporter,
  logExporter,
  metricReader,
  spanProcessor: new BatchSpanProcessor(traceExporter, {
    maxExportBatchSize:
      parseInt(process.env.OTEL_BSP_MAX_EXPORT_BATCH_SIZE || '') || 512,
    scheduledDelayMillis:
      parseInt(process.env.OTEL_BSP_SCHEDULE_DELAY || '') || 5_000,
  }),
  instrumentations: [
    getNodeAutoInstrumentations({
      '@opentelemetry/instrumentation-http': {},
      '@opentelemetry/instrumentation-express': {},
      '@opentelemetry/instrumentation-pg': {},
      '@opentelemetry/instrumentation-grpc': {},
      '@opentelemetry/instrumentation-dns': {},
    }),
  ],
})

// ── Lifecycle ────────────────────────────────────────────────
export async function startTelemetry(): Promise<void> {
  try {
    await sdk.start()
    console.log('[otel] SDK started — service:', process.env.OTEL_SERVICE_NAME || '')
  } catch (err) {
    console.error('[otel] Failed to start SDK:', err)
    process.exit(1)
  }
}

export async function shutdownTelemetry(): Promise<void> {
  try {
    await sdk.shutdown()
    console.log('[otel] SDK shut down gracefully')
  } catch (err) {
    console.error('[otel] Error during shutdown:', err)
  }
}

// Auto-start unless suppressed (e.g., in tests)
if (process.env.OTEL_SDK_DISABLED !== 'true' && process.env.NODE_ENV !== 'test') {
  startTelemetry()
}

// Graceful shutdown
process.on('SIGTERM', () => {
  shutdownTelemetry().finally(() => process.exit(0))
})
process.on('SIGINT', () => {
  shutdownTelemetry().finally(() => process.exit(0))
})
TYPESCRIPT

# ── Install instructions ─────────────────────────────────────
echo ""
echo "=== OpenTelemetry scaffold created ==="
echo "  File : $FILE"
echo ""
echo "Next steps:"
echo "  1. Install dependencies:"
echo "     npm install @opentelemetry/sdk-node @opentelemetry/exporter-trace-otlp-proto"
echo "     npm install @opentelemetry/exporter-metrics-otlp-proto @opentelemetry/exporter-logs-otlp-proto"
echo "     npm install @opentelemetry/auto-instrumentations-node @opentelemetry/semantic-conventions"
echo ""
echo "  2. Add to your entrypoint (top of file, before anything else):"
echo '     import "./telemetry/instrumentation"'
echo ""
echo "  3. Set environment variables:"
echo "     OTEL_SERVICE_NAME=$SERVICE_NAME"
echo "     OTEL_EXPORTER_OTLP_ENDPOINT=http://localhost:4318"
echo "     OTEL_SERVICE_VERSION=1.0.0"
echo "     NODE_ENV=production"
echo ""
echo "  4. (Optional) Set sampling:"
echo "     OTEL_TRACES_SAMPLER=traceidratio"
echo "     OTEL_TRACES_SAMPLER_ARG=0.1"
echo ""
